#include<bits/stdc++.h>
using namespace std;
long long cnt[500010],c[500010],blk[500010],val[500010],l[500010],r[500010],cnt1[500010];
long long blksiz;
struct node
{
    long long l,r,id;
    bool operator<(const node&b)const
    {
        if(blk[l]!=blk[b.l])
        {
            return l<b.l;
        }
        return r<b.r;
    }
}q[500010];
long long res,ans[500010];
void add(long long x)
{
    cnt[c[x]]++;
    res=max(res,1ll*cnt[c[x]]*val[c[x]]);
}
void del(long long x)
{
    cnt[c[x]]--;
}
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    blksiz=sqrt(n);
    for(long long i=1;(i-1)*blksiz+1<=n;i++)
    {
        l[i]=(i-1)*blksiz+1;
        r[i]=min(i*blksiz,n);
        for(long long j=l[i];j<=r[i];j++)
        {
            blk[j]=i;
        }
    }
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&c[i]);
        val[i]=c[i];
    }
    sort(val+1,val+1+n);
    long long p=unique(val+1,val+1+n)-val-1;
    for(long long i=1;i<=n;i++)
    {
        c[i]=lower_bound(val+1,val+1+p,c[i])-val;
        if(c[i]>500000)
        {
            return c[i];
        }
    }
    for(long long i=1;i<=m;i++)
    {
        scanf("%lld%lld",&q[i].l,&q[i].r);
        q[i].id=i;
    }
    sort(q+1,q+1+m);
    long long l=1,r=0,lst=-1;
    for(long long i=1;i<=m;i++)
    {
        if(blk[q[i].l]==blk[q[i].r])
        {
            for(long long j=q[i].l;j<=q[i].r;j++)
            {
                cnt1[c[j]]++;
                ans[q[i].id]=max(ans[q[i].id],1ll*cnt1[c[j]]*val[c[j]]);
            }
            for(long long j=q[i].l;j<=q[i].r;j++)
            {
                cnt1[c[j]]--;
            }
            continue;
        }
        if(blk[q[i].l]!=lst)
        {
            while(r>::r[blk[q[i].l]])
            {
                del(r);
                r--;
            }
            while(l<::r[blk[q[i].l]]+1)
            {
                del(l);
                l++;
            }
            res=0;
            lst=blk[q[i].l];
        }
        while(r<q[i].r)
        {
            r++;
            add(r);
        }
        long long L=l;
        long long tmp=res;
        while(L>q[i].l)
        {
            L--;
            add(L);
        }
        ans[q[i].id]=res;
        while(L<l)
        {
            del(L);
            L++;
        }
        res=tmp;
    }
    for(long long i=1;i<=m;i++)
    {
        printf("%lld\n",ans[i]);
    }
    return 0;
}
